import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    best_score = float('inf')
    best_node = None

    for i, customer_pos in enumerate(unvisited_customers):
        time_window = time_windows[i]
        distance = np.linalg.norm(customer_pos - cur_truck_pos)
        arrival_time = current_time + (distance / truck_speed)

        if arrival_time < time_window[0]:
            wait_time = time_window[0] - arrival_time
            penalty = 0
        elif arrival_time > time_window[1]:
            wait_time = 0
            penalty = (arrival_time - time_window[1]) * 1000
        else:
            wait_time = 0
            penalty = 0

        score = distance + penalty + wait_time

        for other_truck_pos in all_truck_pos:
            if not np.array_equal(other_truck_pos, cur_truck_pos) and np.linalg.norm(customer_pos - other_truck_pos) < distance:
                score += 1000

        if score < best_score:
            best_score = score
            best_node = i

    return best_node
